// 执行 GB/T 9704 国标公文排版
var doc = Application.ActiveDocument;
var sel = doc.Selection;

// 获取所有段落
var paragraphs = doc.Paragraphs;
var paraCount = paragraphs.Count;

// 设置页面边距（上 3.7cm，下 3.5cm，左 2.8cm，右 2.6cm）
var pageSetup = doc.PageSetup;
pageSetup.TopMargin = 3.7 * 28.35; // 转换为磅
pageSetup.BottomMargin = 3.5 * 28.35;
pageSetup.LeftMargin = 2.8 * 28.35;
pageSetup.RightMargin = 2.6 * 28.35;

// 设置页脚距离边界 3.5cm
pageSetup.FooterDistance = 3.5 * 28.35;

// 遍历段落进行格式设置
for (var i = 1; i <= paraCount; i++) {
    var para = paragraphs.Item(i);
    var text = para.Range.Text;
    text = text.replace('\r', ''); // 去除段落标记

    // 判断段落类型并设置格式
    if (text.indexOf("国办发") !== -1 || text.indexOf("文件") !== -1) {
        // 发文机关标志：小标宋体，红色，居中
        para.Range.Font.Name = "SimSun";
        para.Range.Font.Size = 36;
        para.Range.Font.Color.RGB = 255 * 65536 + 0 * 256 + 0; // 红色
        para.Alignment = 1; // 居中
        para.SpaceBefore = 300;
        para.SpaceAfter = 0;
    } 
    else if (text.indexOf("〔") !== -1 && text.indexOf("〕") !== -1) {
        // 发文字号：仿宋_GB2312，三号，居中
        para.Range.Font.Name = "FangSong_GB2312";
        para.Range.Font.Size = 15;
        para.Alignment = 1; // 居中
        para.SpaceBefore = 0;
        para.SpaceAfter = 0;
    }
    else if (text.indexOf("密级") !== -1 || text.indexOf("紧急程度") !== -1) {
        // 密级和紧急程度：仿宋_GB2312，三号，顶格
        para.Range.Font.Name = "FangSong_GB2312";
        para.Range.Font.Size = 15;
        para.Alignment = 0; // 左对齐
        para.SpaceBefore = 0;
        para.SpaceAfter = 0;
    }
    else if (text.trim().length > 0 && text.trim().indexOf(" ") === -1 && text.length < 50) {
        // 标题：二号小标宋体，居中
        para.Range.Font.Name = "SimSun";
        para.Range.Font.Size = 22;
        para.Alignment = 1; // 居中
        para.SpaceBefore = 72;
        para.SpaceAfter = 72;
    }
    else {
        // 正文：三号仿宋_GB2312，首行缩进 2 字符
        para.Range.Font.Name = "FangSong_GB2312";
        para.Range.Font.Size = 15;
        para.Alignment = 0; // 左对齐
        para.FirstLineIndent = 2 * 15; // 首行缩进 2 字符
        para.LineSpacingRule = 1; // 固定值
        para.LineSpacing = 28; // 行间距 28 磅
        para.SpaceBefore = 0;
        para.SpaceAfter = 0;
    }
}

// 设置页码：宋体，四号，底部居中
var sections = doc.Sections;
if (sections.Count > 0) {
    var section = sections.Item(1);
    var footer = section.Footers.Item(1); // 奇数页页脚
    footer.Range.Font.Name = "SimSun";
    footer.Range.Font.Size = 12;
    footer.Range.ParagraphFormat.Alignment = 1; // 居中

    // 插入页码
    if (footer.Range.Text.length === 0) {
        footer.Range.Fields.Add(footer.Range, 4); // wdFieldPage
    }
}

return "已完成 GB/T 9704 国标公文排版，共处理" + paraCount + "个段落";

